/**
 * Which AI backend to run a call against, and its connection details.
 * `Ollama` runs fully on-device; `Anthropic` uploads the prompt (and
 * whatever document text/context it contains) to Anthropic's API.
 */

public enum AiProviderConfig {
    /**
     * Local inference via an Ollama instance. `base_url` defaults to
     * `http://localhost:11434` when not given.
     */
    case ollama(model: String, baseUrl: String?)
    /**
     * Cloud inference via the Anthropic API. `model` defaults to
     * `claude-opus-4-8` when not given. Constructing this variant is
     * itself the user's explicit cloud opt-in — the shell must have
     * obtained the API key from the user, never a bundled default.
     */
    case anthropic(apiKey: String, model: String?)
}

#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
public struct FfiConverterTypeAiProviderConfig: FfiConverterRustBuffer {
    typealias SwiftType = AiProviderConfig

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AiProviderConfig {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        case 1: return try .ollama(model: FfiConverterString.read(from: &buf), baseUrl: FfiConverterOptionString.read(from: &buf))

        case 2: return try .anthropic(apiKey: FfiConverterString.read(from: &buf), model: FfiConverterOptionString.read(from: &buf))

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: AiProviderConfig, into buf: inout [UInt8]) {
        switch value {
        case let .ollama(model, baseUrl):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(model, into: &buf)
            FfiConverterOptionString.write(baseUrl, into: &buf)

        case let .anthropic(apiKey, model):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(apiKey, into: &buf)
            FfiConverterOptionString.write(model, into: &buf)
        }
    }
}

